// src/protocol.ts
import { z } from "zod";
var clientMessageSchema = z.discriminatedUnion("type", [
  z.object({ type: z.literal("input"), data: z.string().min(1) }),
  z.object({ type: z.literal("resize"), cols: z.number().int().min(2), rows: z.number().int().min(2) }),
  z.object({ type: z.literal("typing"), active: z.boolean() }),
  z.object({ type: z.literal("toggle_collab"), enabled: z.boolean() }),
  z.object({ type: z.literal("take_control") }),
  z.object({ type: z.literal("release_control") }),
  z.object({ type: z.literal("ping"), t: z.number() }),
  z.object({ type: z.literal("kill_session") })
]);
var presenceClientSchema = z.object({
  id: z.string(),
  name: z.string(),
  color: z.string(),
  typing: z.boolean(),
  lastActive: z.number()
});
var serverMessageSchema = z.discriminatedUnion("type", [
  z.object({
    type: z.literal("hello"),
    clientId: z.string(),
    roomId: z.string(),
    color: z.string(),
    collabMode: z.boolean(),
    controllerId: z.string().nullable()
  }),
  z.object({
    type: z.literal("presence"),
    clients: z.array(presenceClientSchema)
  }),
  z.object({ type: z.literal("output"), data: z.string() }),
  z.object({
    type: z.literal("snapshot"),
    data: z.string(),
    alternateScreen: z.boolean().optional(),
    cursorHidden: z.boolean().optional()
  }),
  z.object({ type: z.literal("collab"), enabled: z.boolean(), controllerId: z.string().nullable() }),
  z.object({ type: z.literal("input_rejected"), reason: z.string() }),
  z.object({ type: z.literal("error"), message: z.string() }),
  z.object({
    type: z.literal("session_ended"),
    exitCode: z.number().int().nullable(),
    signal: z.string().nullable(),
    message: z.string()
  }),
  z.object({
    type: z.literal("session_renamed"),
    displayName: z.string()
  }),
  z.object({
    type: z.literal("cwd_changed"),
    cwd: z.string()
  }),
  z.object({ type: z.literal("pong"), t: z.number() }),
  // Broadcast when active user's terminal size should be followed
  z.object({ type: z.literal("active_size"), clientId: z.string(), cols: z.number().int(), rows: z.number().int() })
]);
var parseClientMessage = (payload) => {
  const parsed = JSON.parse(payload);
  return clientMessageSchema.parse(parsed);
};
var safeParseClientMessage = (payload) => {
  try {
    const parsed = JSON.parse(payload);
    const result = clientMessageSchema.safeParse(parsed);
    return result.success ? result.data : null;
  } catch {
    return null;
  }
};
var parseServerMessage = (payload) => {
  const parsed = JSON.parse(payload);
  return serverMessageSchema.parse(parsed);
};
var safeParseServerMessage = (payload) => {
  try {
    const parsed = JSON.parse(payload);
    const result = serverMessageSchema.safeParse(parsed);
    return result.success ? result.data : null;
  } catch {
    return null;
  }
};

// src/colors.ts
var PRESENCE_COLORS = [
  "#e67e22",
  "#1abc9c",
  "#3498db",
  "#e74c3c",
  "#9b59b6",
  "#2ecc71",
  "#f1c40f",
  "#16a085",
  "#d35400",
  "#2980b9"
];
var pickPresenceColor = (index) => {
  return PRESENCE_COLORS[index % PRESENCE_COLORS.length];
};
export {
  PRESENCE_COLORS,
  clientMessageSchema,
  parseClientMessage,
  parseServerMessage,
  pickPresenceColor,
  presenceClientSchema,
  safeParseClientMessage,
  safeParseServerMessage,
  serverMessageSchema
};
